import{_ as l,o as i,c as e,ai as r}from"./chunks/framework.ampVZV4B.js";const b=JSON.parse('{"title":"AI 快速入门（7 天）","description":"","frontmatter":{},"headers":[],"relativePath":"ai/quickstart.md","filePath":"ai/quickstart.md"}'),o={name:"ai/quickstart.md"};function d(t,a,c,n,s,h){return i(),e("div",null,[...a[0]||(a[0]=[r('<h1 id="ai-快速入门-7-天" tabindex="-1">AI 快速入门（7 天） <a class="header-anchor" href="#ai-快速入门-7-天" aria-label="Permalink to “AI 快速入门（7 天）”">​</a></h1><blockquote><p>目标：先快速上手，再逐步深入。<br> 适合你现在的阶段：普通开发者，希望先把 AI 用起来，随后做成可讲的项目。</p></blockquote><hr><h2 id="学习原则-先记住这-3-条" tabindex="-1">学习原则（先记住这 3 条） <a class="header-anchor" href="#学习原则-先记住这-3-条" aria-label="Permalink to “学习原则（先记住这 3 条）”">​</a></h2><ol><li><strong>先会用，再懂原理</strong>：先把 API 和常见场景跑通。</li><li><strong>先单工具闭环，再多工具编排</strong>：不要一上来做复杂 Agent。</li><li><strong>每一步都产出可复用成果</strong>：Prompt 模板、脚本、小项目页面。</li></ol><hr><h2 id="_7-天安排-可压缩到-3-5-天" tabindex="-1">7 天安排（可压缩到 3-5 天） <a class="header-anchor" href="#_7-天安排-可压缩到-3-5-天" aria-label="Permalink to “7 天安排（可压缩到 3-5 天）”">​</a></h2><h3 id="day-1-熟悉模型与提问方式" tabindex="-1">Day 1：熟悉模型与提问方式 <a class="header-anchor" href="#day-1-熟悉模型与提问方式" aria-label="Permalink to “Day 1：熟悉模型与提问方式”">​</a></h3><ul><li>选 1-2 个模型平台（如 GPT / 通义）。</li><li>练 3 个场景：代码解释、报错排查、文档总结。</li><li>产出：你的「常用提问模板」初版。</li></ul><h3 id="day-2-prompt-基础模板" tabindex="-1">Day 2：Prompt 基础模板 <a class="header-anchor" href="#day-2-prompt-基础模板" aria-label="Permalink to “Day 2：Prompt 基础模板”">​</a></h3><ul><li>固定模板：角色、目标、输入格式、输出格式。</li><li>用模板改写你现有文档中的 2 篇内容。</li><li>产出：<code>Prompt 模板库 v1</code>。</li></ul><h3 id="day-3-api-最小调用" tabindex="-1">Day 3：API 最小调用 <a class="header-anchor" href="#day-3-api-最小调用" aria-label="Permalink to “Day 3：API 最小调用”">​</a></h3><ul><li>选 Java / Node / Python 任一语言，跑通一次 API 调用。</li><li>命令行输入问题，输出模型结果。</li><li>产出：<code>llm-demo</code> 最小脚本。</li></ul><h3 id="day-4-第一个实用小工具" tabindex="-1">Day 4：第一个实用小工具 <a class="header-anchor" href="#day-4-第一个实用小工具" aria-label="Permalink to “Day 4：第一个实用小工具”">​</a></h3><ul><li>做「面试问答生成器」或「笔记总结器」。</li><li>输入一个主题，输出 Markdown 文件。</li><li>产出：可复用的小工具 1 个。</li></ul><h3 id="day-5-agent-最小闭环-单工具" tabindex="-1">Day 5：Agent 最小闭环（单工具） <a class="header-anchor" href="#day-5-agent-最小闭环-单工具" aria-label="Permalink to “Day 5：Agent 最小闭环（单工具）”">​</a></h3><ul><li>给模型接一个工具（文件读写 / 简单 HTTP）。</li><li>让模型“先调工具，再组织输出”。</li><li>产出：<code>单 Agent + 单工具</code> Demo。</li></ul><h3 id="day-6-接入你的知识库" tabindex="-1">Day 6：接入你的知识库 <a class="header-anchor" href="#day-6-接入你的知识库" aria-label="Permalink to “Day 6：接入你的知识库”">​</a></h3><ul><li>从 <code>docs/</code> 中读取指定模块内容，提供上下文给模型。</li><li>不做复杂 RAG，先做“可控上下文”。</li><li>产出：可在你仓库里实用的学习助手原型。</li></ul><h3 id="day-7-复盘-进入深入路线" tabindex="-1">Day 7：复盘 + 进入深入路线 <a class="header-anchor" href="#day-7-复盘-进入深入路线" aria-label="Permalink to “Day 7：复盘 + 进入深入路线”">​</a></h3><ul><li>回看一周产出：模板、脚本、Demo。</li><li>补齐一页项目说明：目标、输入输出、效果、后续计划。</li><li>产出：可用于面试讲述的 AI 小项目材料。</li></ul><hr><h2 id="下一步怎么深入" tabindex="-1">下一步怎么深入 <a class="header-anchor" href="#下一步怎么深入" aria-label="Permalink to “下一步怎么深入”">​</a></h2><ul><li><strong>先走主路径</strong>：<code>/ai/llm-basics</code> → <code>/ai/agent-basics</code> → <code>/ai/mvp-server</code></li><li><strong>再选修进阶</strong>：<code>/ai/multimodal-kg</code> → <code>/ai/mlops-platform</code></li><li><strong>要按文章练习</strong>：看 <code>stage-1/2/3</code> 模块化文章</li></ul><hr><h2 id="本页对应站内入口" tabindex="-1">本页对应站内入口 <a class="header-anchor" href="#本页对应站内入口" aria-label="Permalink to “本页对应站内入口”">​</a></h2><ul><li>路线总览：<code>/ai/ai-roadmap</code></li><li>主路径第一站：<code>/ai/llm-basics</code></li><li>模块化练习入口：<code>/ai/stage-1-llm/</code></li></ul>',27)])])}const u=l(o,[["render",d]]);export{b as __pageData,u as default};
